"""
Parameterized generator for GH193_aiohttp_11842.

Source PR:    https://github.com/aio-libs/aiohttp/pull/11842
Source Issue: N/A

Seed varies: renames 'actions' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH193_aiohttp_11842'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH193_aiohttp_11842'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('actions', 'actions' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH193_aiohttp_11842',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'aio-libs/aiohttp',
                "pr_number": 11842,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/aio-libs/aiohttp/pull/11842",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            '.github/workflows/ci-cd.yml': 'name: CI\n\non:\n  merge_group:\n  push:\n    branches:\n      - \'master\'\n      - \'[0-9].[0-9]+\'  # matches to backport branches, e.g. 3.6\n    tags: [ \'v*\' ]\n  pull_request:\n    branches:\n      - \'master\'\n      - \'[0-9].[0-9]+\'\n  schedule:\n    - cron:  \'0 6 * * *\'  # Daily 6AM UTC build\n\nconcurrency:\n  group: ${{ github.workflow }}-${{ github.event.pull_request.number || github.sha }}\n  cancel-in-progress: true\n\nenv:\n  COLOR: yes\n  FORCE_COLOR: 1  # Request colored output from CLI tools supporting it\n  MYPY_FORCE_COLOR: 1\n  PY_COLORS: 1\n\npermissions: {}\njobs:\n\n  lint:\n    permissions:\n      contents: read # to fetch code (actions/checkout)\n\n    name: Linter\n    runs-on: ubuntu-latest\n    timeout-minutes: 5\n    steps:\n    - name: Checkout\n      uses: actions/checkout@v6\n      with:\n        submodules: true\n    - name: >-\n        Verify that `requirements/runtime-deps.in`\n        is in sync with `pyproject.toml`\n      run: |\n        set -eEuo pipefail\n        make sync-direct-runtime-deps\n        git diff --exit-code -- requirements/runtime-deps.in\n    - name: Setup Python\n      uses: actions/setup-python@v6\n      with:\n        python-version: 3.11\n    - name: Cache PyPI\n      uses: actions/cache@v5.0.0\n      with:\n        key: pip-lint-${{ hashFiles(\'requirements/*.txt\') }}\n        path: ~/.cache/pip\n        restore-keys: |\n            pip-lint-\n    - name: Update pip, wheel, setuptools, build, twine\n      run: |\n        python -m pip install -U pip wheel setuptools build twine\n    - name: Install dependencies\n      run: |\n        python -m pip install -r requirements/lint.in -c requirements/lint.txt\n    - name: Install self\n      run: |\n        python -m pip install . -c requirements/runtime-deps.txt\n      env:\n        AIOHTTP_NO_EXTENSIONS: 1\n    - name: Run mypy\n      run: |\n        make mypy\n    - name: Run slotscheck\n      run: |\n        # Some extra requirements are needed to ensure all modules\n        # can be scanned by slotscheck.\n        pip install -r requirements/base.in -c requirements/base.txt\n        slotscheck -v -m aiohttp\n    - name: Install spell checker\n      run: |\n        pip install -r requirements/doc-spelling.in -c requirements/doc-spelling.txt\n    - name: Run docs spelling\n      run: |\n        # towncrier --yes  # uncomment me after publishing a release\n        make doc-spelling\n    - name: Build package\n      run: |\n        python -m build\n      env:\n        AIOHTTP_NO_EXTENSIONS: 1\n    - name: Run twine checker\n      run: |\n        twine check --strict dist/*\n    - name: Making sure that CONTRIBUTORS.txt remains sorted\n      run: |\n        LC_ALL=C sort --check --ignore-case CONTRIBUTORS.txt\n\n  gen_llhttp:\n    permissions:\n      contents: read # to fetch code (actions/checkout)\n\n    name: Generate llhttp sources\n    runs-on: ubuntu-latest\n    timeout-minutes: 5\n    steps:\n    - name: Checkout\n      uses: actions/checkout@v6\n      with:\n        submodules: true\n    - name: Cache llhttp generated files\n      uses: actions/cache@v5.0.0\n      id: cache\n      with:\n        key: llhttp-${{ hashFiles(\'vendor/llhttp/package*.json\', \'vendor/llhttp/src/**/*\') }}\n        path:  vendor/llhttp/build\n    - name: Setup NodeJS\n      if: steps.cache.outputs.cache-hit != \'true\'\n      uses: actions/setup-node@v6\n      with:\n        node-version: 18\n    - name: Generate llhttp sources\n      if: steps.cache.outputs.cache-hit != \'true\'\n      run: |\n        make generate-llhttp\n    - name: Upload llhttp generated files\n      uses: actions/upload-artifact@v6\n      with:\n        name: llhttp\n        path: vendor/llhttp/build\n        if-no-files-found: error\n\n  test:\n    permissions:\n      contents: read # to fetch code (actions/checkout)\n\n    name: Test\n    needs: gen_llhttp\n    strategy:\n      matrix:\n        pyver: [\'3.10\', \'3.11\', \'3.12\', \'3.13\', \'3.14\']\n        no-extensions: [\'\', \'Y\']\n        os: [ubuntu, macos, windows]\n        experimental: [false]\n        exclude:\n          - os: macos\n            no-extensions: \'Y\'\n          - os: windows\n            no-extensions: \'Y\'\n        include:\n          - pyver: pypy-3.11\n            no-extensions: \'Y\'\n            os: ubuntu\n            experimental: false\n          - os: ubuntu\n            pyver: "3.14t"\n            no-extensions: \'\'\n            experimental: false\n      fail-fast: true\n    runs-on: ${{ matrix.os }}-latest\n    continue-on-error: ${{ matrix.experimental }}\n    steps:\n    - name: Checkout\n      uses: actions/checkout@v6\n      with:\n        submodules: true\n    - name: Setup Python ${{ matrix.pyver }}\n      id: python-install\n      uses: actions/setup-python@v6\n      with:\n        allow-prereleases: true\n        python-version: ${{ matrix.pyver }}\n    - name: Get pip cache dir\n      id: pip-cache\n      run: |\n        echo "dir=$(pip cache dir)" >> "${GITHUB_OUTPUT}"\n      shell: bash\n    - name: Cache PyPI\n      uses: actions/cache@v5.0.0\n      with:\n        key: pip-ci-${{ runner.os }}-${{ matrix.pyver }}-${{ matrix.no-extensions }}-${{ hashFiles(\'requirements/*.txt\') }}\n        path: ${{ steps.pip-cache.outputs.dir }}\n        restore-keys: |\n            pip-ci-${{ runner.os }}-${{ matrix.pyver }}-${{ matrix.no-extensions }}-\n    - name: Update pip, wheel, setuptools, build, twine\n      run: |\n        python -m pip install -U pip wheel setuptools build twine\n    - name: Install dependencies\n      env:\n        DEPENDENCY_GROUP: test${{ endsWith(matrix.pyver, \'t\') && \'-ft\' || \'\' }}\n      run: |\n        python -Im pip install -r requirements/${{ env.DEPENDENCY_GROUP }}.in -c requirements/${{ env.DEPENDENCY_GROUP }}.txt\n    - name: Set PYTHON_GIL=0 for free-threading builds\n      if: ${{ endsWith(matrix.pyver, \'t\') }}\n      run: echo "PYTHON_GIL=0" >> $GITHUB_ENV\n    - name: Restore llhttp generated files\n      if: ${{ matrix.no-extensions == \'\' }}\n      uses: actions/download-artifact@v6\n      with:\n        name: llhttp\n        path: vendor/llhttp/build/\n    - name: Cythonize\n      if: ${{ matrix.no-extensions == \'\' }}\n      run: |\n        make cythonize\n    - name: Install self\n      env:\n        AIOHTTP_NO_EXTENSIONS: ${{ matrix.no-extensions }}\n      run: python -m pip install -e .\n    - name: Run unittests\n      env:\n        COLOR: yes\n        AIOHTTP_NO_EXTENSIONS: ${{ matrix.no-extensions }}\n        PIP_USER: 1\n      run: >-\n        PATH="${HOME}/Library/Python/3.11/bin:${HOME}/.local/bin:${PATH}"\n        pytest --junitxml=junit.xml\n      shell: bash\n    - name: Re-run the failing tests with maximum verbosity\n      if: failure()\n      env:\n        COLOR: yes\n        AIOHTTP_NO_EXTENSIONS: ${{ matrix.no-extensions }}\n      run: >-  # `exit 1` makes sure that the job remains red with flaky runs\n        pytest --no-cov --numprocesses=0 -vvvvv --lf && exit 1\n      shell: bash\n    - name: Run dev_mode tests\n      env:\n        COLOR: yes\n        AIOHTTP_NO_EXTENSIONS: ${{ matrix.no-extensions }}\n        PIP_USER: 1\n        PYTHONDEVMODE: 1\n      run: pytest -m dev_mode --cov-append --numprocesses=0\n      shell: bash\n    - name: Turn coverage into xml\n      env:\n        COLOR: \'yes\'\n        PIP_USER: 1\n      run: |\n        python -m coverage xml\n    - name: Upload coverage\n      uses: codecov/codecov-action@v5\n      with:\n        file: ./coverage.xml\n        flags: >-\n          CI-GHA,OS-${{\n            runner.os\n          }},VM-${{\n            matrix.os\n          }},Py-${{\n            steps.python-install.outputs.python-version\n          }}\n        token: ${{ secrets.CODECOV_TOKEN }}\n    - name: Upload test results to Codecov\n      if: ${{ !cancelled() }}\n      uses: codecov/test-results-action@v1\n      with:\n        token: ${{ secrets.CODECOV_TOKEN }}\n\n  benchmark:\n    name: Benchmark\n    needs: gen_llhttp\n\n    runs-on: ubuntu-latest\n    timeout-minutes: 12\n    steps:\n    - name: Checkout project\n      uses: actions/checkout@v6\n      with:\n        submodules: true\n    - name: Setup Python 3.13.2\n      id: python-install\n      uses: actions/setup-python@v6\n      with:\n        python-version: 3.13.2\n        cache: pip\n        cache-dependency-path: requirements/*.txt\n    - name: Update pip, wheel, setuptools, build, twine\n      run: |\n        python -m pip install -U pip wheel setuptools build twine\n    - name: Install dependencies\n      run: |\n        python -m pip install -r requirements/test.in -c requirements/test.txt\n    - name: Restore llhttp generated files\n      uses: actions/download-artifact@v6\n      with:\n        name: llhttp\n        path: vendor/llhttp/build/\n    - name: Cythonize\n      run: |\n        make cythonize\n    - name: Install self\n      run: python -m pip install -e .\n    - name: Run benchmarks\n      uses: CodSpeedHQ/action@v4\n      with:\n        mode: instrumentation\n        token: ${{ secrets.CODSPEED_TOKEN }}\n        run: python -Im pytest --no-cov --numprocesses=0 -vvvvv --codspeed\n\n\n  check:  # This job does nothing and is only used for the branch protection\n    if: always()\n\n    needs:\n    - lint\n    - test\n\n    runs-on: ubuntu-latest\n\n    steps:\n    - name: Decide whether the needed jobs succeeded or failed\n      uses: re-actors/alls-green@release/v1\n      with:\n        jobs: ${{ toJSON(needs) }}\n\n  pre-deploy:\n    name: Pre-Deploy\n    runs-on: ubuntu-latest\n    needs: check\n    # Run only on pushing a tag\n    if: github.event_name == \'push\' && contains(github.ref, \'refs/tags/\')\n    steps:\n      - name: Dummy\n        run: |\n            echo "Predeploy step"\n\n  build-tarball:\n    permissions:\n      contents: read # to fetch code (actions/checkout)\n\n    name: Tarball\n    runs-on: ubuntu-latest\n    needs: pre-deploy\n    steps:\n    - name: Checkout\n      uses: actions/checkout@v6\n      with:\n        submodules: true\n    - name: Setup Python\n      uses: actions/setup-python@v6\n    - name: Update pip, wheel, setuptools, build, twine\n      run: |\n        python -m pip install -U pip wheel setuptools build twine\n    - name: Install cython\n      run: >-\n        python -m\n        pip install -r requirements/cython.in -c requirements/cython.txt\n    - name: Restore llhttp generated files\n      uses: actions/download-artifact@v6\n      with:\n        name: llhttp\n        path: vendor/llhttp/build/\n    - name: Cythonize\n      run: |\n        make cythonize\n    - name: Make sdist\n      run: |\n        python -m build --sdist\n    - name: Upload artifacts\n      uses: actions/upload-artifact@v6\n      with:\n        name: dist-sdist\n        path: dist\n\n  build-wheels:\n    permissions:\n      contents: read # to fetch code (actions/checkout)\n\n    name: Build wheels on ${{ matrix.os }} ${{ matrix.qemu }} ${{ matrix.musl }}\n    runs-on: ${{ matrix.os }}\n    needs: pre-deploy\n    strategy:\n      matrix:\n        os: ["ubuntu-latest", "windows-latest", "macos-latest", "ubuntu-24.04-arm"]\n        qemu: [\'\']\n        musl: [""]\n        include:\n          # Split ubuntu/musl jobs for the sake of speed-up\n        - os: ubuntu-latest\n          qemu: ppc64le\n          musl: ""\n        - os: ubuntu-latest\n          qemu: ppc64le\n          musl: musllinux\n        - os: ubuntu-latest\n          qemu: riscv64\n          musl: ""\n        - os: ubuntu-latest\n          qemu: riscv64\n          musl: musllinux\n        - os: ubuntu-latest\n          qemu: s390x\n          musl: ""\n        - os: ubuntu-latest\n          qemu: s390x\n          musl: musllinux\n        - os: ubuntu-latest\n          qemu: armv7l\n          musl: ""\n        - os: ubuntu-latest\n          qemu: armv7l\n          musl: musllinux\n        - os: ubuntu-latest\n          musl: musllinux\n        - os: ubuntu-24.04-arm\n          musl: musllinux\n    steps:\n    - name: Checkout\n      uses: actions/checkout@v6\n      with:\n        submodules: true\n    - name: Set up QEMU\n      if: ${{ matrix.qemu }}\n      uses: docker/setup-qemu-action@v3\n      with:\n        platforms: all\n        # This should be temporary\n        # xref https://github.com/docker/setup-qemu-action/issues/188\n        # xref https://github.com/tonistiigi/binfmt/issues/215\n        image: tonistiigi/binfmt:qemu-v8.1.5\n      id: qemu\n    - name: Prepare emulation\n      run: |\n        if [[ -n "${{ matrix.qemu }}" ]]; then\n          # Build emulated architectures only if QEMU is set,\n          # use default "auto" otherwise\n          echo "CIBW_ARCHS_LINUX=${{ matrix.qemu }}" >> $GITHUB_ENV\n        fi\n      shell: bash\n    - name: Setup Python\n      uses: actions/setup-python@v6\n      with:\n        python-version: 3.x\n    - name: Update pip, wheel, setuptools, build, twine\n      run: |\n        python -m pip install -U pip wheel setuptools build twine\n    - name: Install cython\n      run: >-\n        python -m\n        pip install -r requirements/cython.in -c requirements/cython.txt\n    - name: Restore llhttp generated files\n      uses: actions/download-artifact@v6\n      with:\n        name: llhttp\n        path: vendor/llhttp/build/\n    - name: Cythonize\n      run: |\n        make cythonize\n    - name: Build wheels\n      uses: pypa/cibuildwheel@v3.3.0\n      env:\n        CIBW_SKIP: pp* ${{ matrix.musl == \'musllinux\' && \'*manylinux*\' || \'*musllinux*\' }}\n        CIBW_ARCHS_MACOS: x86_64 arm64 universal2\n    - name: Upload wheels\n      uses: actions/upload-artifact@v6\n      with:\n        name: >-\n          dist-${{ matrix.os }}-${{ matrix.musl }}-${{\n            matrix.qemu\n            && matrix.qemu\n            || \'native\'\n          }}\n        path: ./wheelhouse/*.whl\n\n  deploy:\n    name: Deploy\n    needs: [build-tarball, build-wheels]\n    runs-on: ubuntu-latest\n\n    permissions:\n      contents: write  # IMPORTANT: mandatory for making GitHub Releases\n      id-token: write  # IMPORTANT: mandatory for trusted publishing & sigstore\n\n    environment:\n      name: pypi\n      url: https://pypi.org/p/aiohttp\n\n    steps:\n    - name: Checkout\n      uses: actions/checkout@v6\n      with:\n        submodules: true\n    - name: Login\n      run: |\n        echo "${{ secrets.GITHUB_TOKEN }}" | gh auth login --with-token\n    - name: Download distributions\n      uses: actions/download-artifact@v6\n      with:\n        path: dist\n        pattern: dist-*\n        merge-multiple: true\n    - name: Collected dists\n      run: |\n        tree dist\n    - name: Make Release\n      uses: aio-libs/create-release@v1.6.6\n      with:\n        changes_file: CHANGES.rst\n        name: aiohttp\n        version_file: aiohttp/__init__.py\n        github_token: ${{ secrets.GITHUB_TOKEN }}\n        dist_dir: dist\n        fix_issue_regex: >-\n          :issue:`(\\d+)`\n        fix_issue_repl: >-\n          #\\1\n\n    - name: >-\n        Publish 🐍📦 to PyPI\n      uses: pypa/gh-action-pypi-publish@release/v1\n\n    - name: Sign the dists with Sigstore\n      uses: sigstore/gh-action-sigstore-python@v3.2.0\n      with:\n        inputs: >-\n          ./dist/*.tar.gz\n          ./dist/*.whl\n\n    - name: Upload artifact signatures to GitHub Release\n      # Confusingly, this action also supports updating releases, not\n      # just creating them. This is what we want here, since we\'ve manually\n      # created the release above.\n      uses: softprops/action-gh-release@v2\n      with:\n        # dist/ contains the built packages, which smoketest-artifacts/\n        # contains the signatures and certificates.\n        files: dist/**\n',
        }
